from datetime import datetime

def _log_error_char(universe, name, key):
    try:
        with open("error_chars.txt", "a", encoding="utf-8") as f:
            f.write(
                f"[{datetime.utcnow().isoformat()}] "
                f"universe={universe} | "
                f"name={name} | "
                f"key={key}\n"
            )
    except Exception:
        pass  # лог никогда не должен ломать код


